import{_ as r,o as a,c as l,a0 as o}from"./chunks/framework.Dx25mwie.js";const _=JSON.parse('{"title":"魷魚螺肉蒜 — 複刻50年前的古早味豪華年菜","description":"台菜一姐的經典台式古早味年菜，乾魷魚不用泡水直接煮，螺肉最後才加，排骨溫水汆燙。","frontmatter":{"title":"魷魚螺肉蒜 — 複刻50年前的古早味豪華年菜","description":"台菜一姐的經典台式古早味年菜，乾魷魚不用泡水直接煮，螺肉最後才加，排骨溫水汆燙。"},"headers":[],"relativePath":"docs/中式/魷魚螺肉蒜.md","filePath":"docs/中式/魷魚螺肉蒜.md"}'),e={name:"docs/中式/魷魚螺肉蒜.md"};function i(d,t,n,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="魷魚螺肉蒜-—-複刻50年前的古早味豪華年菜" tabindex="-1">魷魚螺肉蒜 — 複刻50年前的古早味豪華年菜 <a class="header-anchor" href="#魷魚螺肉蒜-—-複刻50年前的古早味豪華年菜" aria-label="Permalink to &quot;魷魚螺肉蒜 — 複刻50年前的古早味豪華年菜&quot;">​</a></h1><blockquote><p><strong>來源</strong>: <a href="https://youtu.be/2L_UdWV0n0Q" target="_blank" rel="noreferrer">YouTube - 台菜一姐</a><strong>頻道</strong>: 台菜一姐 @ladyfirst0302 <strong>分享日期</strong>: 2026/06/08 <strong>分類</strong>: 中式/台式</p></blockquote><hr><h2 id="食材" tabindex="-1">食材 <a class="header-anchor" href="#食材" aria-label="Permalink to &quot;食材&quot;">​</a></h2><table tabindex="0"><thead><tr><th>食材</th><th>份量</th><th>備註</th></tr></thead><tbody><tr><td>排骨</td><td>半斤 (600g)</td><td>約2支</td></tr><tr><td>乾魷魚</td><td>1 隻</td><td>不用泡水</td></tr><tr><td>螺肉罐頭</td><td>1 罐</td><td>湯汁留用</td></tr><tr><td>蒜苗</td><td>適量</td><td>蒜白切粗段，蒜尾切細</td></tr><tr><td>桶筍</td><td>1 支</td><td>或新鮮筍</td></tr><tr><td>乾香菇</td><td>3 朵</td><td>洗兩三次再泡水</td></tr><tr><td>鹽</td><td>1 鹽匙</td><td></td></tr><tr><td>米酒頭</td><td>1 湯匙</td><td></td></tr><tr><td>白胡椒粉</td><td>適量</td><td></td></tr></tbody></table><hr><h2 id="步驟" tabindex="-1">步驟 <a class="header-anchor" href="#步驟" aria-label="Permalink to &quot;步驟&quot;">​</a></h2><h3 id="_1-排骨汆燙" tabindex="-1">1. 排骨汆燙 <a class="header-anchor" href="#_1-排骨汆燙" aria-label="Permalink to &quot;1. 排骨汆燙&quot;">​</a></h3><ul><li>冷水下鍋，<strong>溫水</strong>就放入排骨（不要滾水，肉會柴）</li><li>煮到冒泡出些許血水 → 關火</li><li><strong>浸泡 3-5 分鐘</strong>讓血水繼續吐出來</li><li>撈出沖洗</li></ul><h3 id="_2-備料" tabindex="-1">2. 備料 <a class="header-anchor" href="#_2-備料" aria-label="Permalink to &quot;2. 備料&quot;">​</a></h3><ul><li><strong>乾魷魚</strong>：去殼、去中間骨頭，剪成條狀（<strong>不用泡水</strong>，直接煮甜味才不會流失）</li><li><strong>桶筍</strong>：切片</li><li><strong>蒜苗</strong>：蒜白切粗段，蒜尾切細</li><li><strong>香菇</strong>：洗兩三次後泡水，香菇水留用</li></ul><h3 id="_3-煸魷魚" tabindex="-1">3. 煸魷魚 <a class="header-anchor" href="#_3-煸魷魚" aria-label="Permalink to &quot;3. 煸魷魚&quot;">​</a></h3><ul><li>少許油，<strong>小火</strong>煸到酥香（有烤魷魚的味道即可）</li><li>⚠️ 不能焦，焦了湯會苦</li></ul><h3 id="_4-入鍋" tabindex="-1">4. 入鍋 <a class="header-anchor" href="#_4-入鍋" aria-label="Permalink to &quot;4. 入鍋&quot;">​</a></h3><ul><li>煸好的魷魚 + 桶筍 + 香菇（連香菇水）</li><li>加水至 <strong>七分滿</strong></li><li>調味：1 鹽匙鹽、1 湯匙米酒頭、<strong>3 湯匙螺肉湯汁</strong>（先加部分做底味）</li></ul><h3 id="_5-電鍋蒸" tabindex="-1">5. 電鍋蒸 <a class="header-anchor" href="#_5-電鍋蒸" aria-label="Permalink to &quot;5. 電鍋蒸&quot;">​</a></h3><ul><li>外鍋 <strong>1 杯水</strong></li><li>跳起後 <strong>再燜 20 分鐘</strong>（排骨才會軟爛）</li></ul><h3 id="_6-最後調味" tabindex="-1">6. 最後調味 <a class="header-anchor" href="#_6-最後調味" aria-label="Permalink to &quot;6. 最後調味&quot;">​</a></h3><ul><li>開火，放入 <strong>蒜白</strong>、<strong>螺肉</strong>（⚠️ 螺肉最後才加，一起燉會沒味道）</li><li>試鹹度，<strong>慢慢加螺肉湯汁</strong>調整（螺肉滾了還會跑鹹度出來）</li><li>水滾後放 <strong>蒜尾</strong></li><li>加 <strong>白胡椒粉</strong></li></ul><h3 id="_7-完成" tabindex="-1">7. 完成 <a class="header-anchor" href="#_7-完成" aria-label="Permalink to &quot;7. 完成&quot;">​</a></h3><ul><li>整鍋約 <strong>600-700 台幣</strong>（食材費）</li><li>人多可多加水和鹽</li></ul><hr><h2 id="主廚秘訣" tabindex="-1">主廚秘訣 <a class="header-anchor" href="#主廚秘訣" aria-label="Permalink to &quot;主廚秘訣&quot;">​</a></h2><ul><li>🔑 <strong>乾魷魚不用泡水</strong> — 直接煮，甜味鎖在湯裡</li><li>🔑 <strong>螺肉最後加</strong> — 保持口感，味道不會被煮散</li><li>🔑 <strong>排骨溫水汆燙</strong> — 肉才不會柴</li><li>🔑 <strong>煸魷魚小火</strong> — 焦了整鍋湯會苦</li><li>🔑 <strong>桶筍加分</strong> — 酸香氣味和湯頭絕配</li></ul><hr><p><em>由 Hermes 於 2026/06/08 整理</em></p>',26)])])}const c=r(e,[["render",i]]);export{_ as __pageData,c as default};
